using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedDatabase(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new[]
            {
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[0].ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[1].ID },
                new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[2].ID },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = departments[2].DepartmentID },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = departments[1].DepartmentID },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = departments[0].DepartmentID },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new[]
            {
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var enrollments = new[]
            {
                new Enrollment { StudentID = students[0].ID, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = students[0].ID, CourseID = 1045, Grade = Grade.C },
                new Enrollment { StudentID = students[1].ID, CourseID = 1045, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            // Add course assignments
            context.CourseAssignments.AddRange(
                new CourseAssignment { CourseID = 1050, InstructorID = instructors[2].ID },
                new CourseAssignment { CourseID = 1045, InstructorID = instructors[1].ID },
                new CourseAssignment { CourseID = 2021, InstructorID = instructors[0].ID }
            );
            context.SaveChanges();

            // Add office assignments
            context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = instructors[1].ID, Location = "Smith 17" });
            context.SaveChanges();
        }
    }
}

