using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        #region Person / Student / Instructor

        [Fact]
        public void Person_FullName_ReturnsConcatenatedName()
        {
            var student = new Student { LastName = "Doe", FirstMidName = "John" };
            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Student_EnrollmentDate_IsRequired()
        {
            var student = new Student { LastName = "Test", FirstMidName = "Test" };
            var context = new ValidationContext(student);
            var results = new List<ValidationResult>();

            // Default DateTime is not DateTime.MinValue for [Required], it's the default struct value
            // which passes Required but might fail Range validation
            Validator.TryValidate(student, context, results, true);
            // The student has default(DateTime) which should fail the Range attribute
        }

        [Fact]
        public void Instructor_FullName_ReturnsConcatenatedName()
        {
            var instructor = new Instructor { LastName = "Smith", FirstMidName = "Jane" };
            Assert.Equal("Smith, Jane", instructor.FullName);
        }

        [Fact]
        public void Instructor_HireDate_Property()
        {
            var date = DateTime.Parse("2023-01-15");
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void Student_Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment> { new Enrollment(), new Enrollment() }
            };
            Assert.Equal(2, student.Enrollments.Count);
        }

        #endregion

        #region Course

        [Fact]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/test/image.jpg"
            };

            Assert.Equal(1001, course.CourseID);
            Assert.Equal("Test Course", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/test/image.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_Collections_CanBeInitialized()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            Assert.Empty(course.Enrollments);
            Assert.Empty(course.CourseAssignments);
        }

        #endregion

        #region Department

        [Fact]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2023-01-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorID_IsNullable()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_RowVersion_IsNullByDefault()
        {
            var dept = new Department();
            Assert.Null(dept.RowVersion);
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_Grade_IsNullable()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Properties_SetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 100,
                StudentID = 200,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(100, enrollment.CourseID);
            Assert.Equal(200, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Grade_Enum_HasCorrectValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 100 };
            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var oa = new OfficeAssignment { InstructorID = 1, Location = "Building A" };
            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Building A", oa.Location);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("Test message", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_Enum_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region ErrorViewModel

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        #endregion

        #region ViewModels

        [Fact]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.AssignedCourseData
            {
                CourseID = 1,
                Title = "Test",
                Assigned = true
            };
            Assert.Equal(1, data.CourseID);
            Assert.Equal("Test", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var group = new ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = DateTime.Parse("2023-01-01"),
                StudentCount = 5
            };
            Assert.Equal(DateTime.Parse("2023-01-01"), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_IsNullable()
        {
            var group = new ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup();
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var data = new ContosoUniversity.Models.SchoolViewModels.InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };
            Assert.Empty(data.Instructors);
            Assert.Empty(data.Courses);
            Assert.Empty(data.Enrollments);
        }

        #endregion
    }
}
