using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new StudentsController(_context);

            // Set up HttpContext with TempData
            var httpContext = new DefaultHttpContext();
            _controller.ControllerContext = new ControllerContext { HttpContext = httpContext };
            _controller.TempData = new TempDataDictionary(httpContext, new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_WithSearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_WithSearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringNull_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_NewSearchString_ResetsToPage1()
        {
            var result = _controller.Index(null, null, "A", 5) as ViewResult;

            Assert.NotNull(result);
            // When a new search string is provided, page resets to 1
            var model = Assert.IsType<PaginatedList<Student>>(result!.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
