using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelper.CreateContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.Find(student.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Test", retrieved!.FirstMidName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Test", retrieved!.FirstMidName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveCourse()
        {
            var dept = new Department { Name = "Test", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 9999, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(9999);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved!.Title);
        }

        [Fact]
        public void Context_CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 50000,
                StartDate = DateTime.Parse("2023-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.Find(dept.DepartmentID);
            Assert.NotNull(retrieved);
            Assert.Equal("TestDept", retrieved!.Name);
        }

        [Fact]
        public void Context_CanAddAndRetrieveEnrollment()
        {
            var student = new Student { FirstMidName = "E", LastName = "Student", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            var dept = new Department { Name = "EDept", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 8888, Title = "ECourse", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = 8888, Grade = Grade.A };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.CourseID == 8888);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void Context_CourseAssignment_HasCompositeKey()
        {
            TestHelper.SeedDatabase(_context);

            var instructor = _context.Instructors.First();
            var course = _context.Courses.First();

            var ca = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            // Composite key works - no exception
            // May or may not find depending on seeding
        }

        [Fact]
        public void Context_Instructor_HasOfficeAssignment()
        {
            TestHelper.SeedDatabase(_context);

            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.LastName == "Fakhouri");

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Smith 17", instructor.OfficeAssignment!.Location);
        }

        [Fact]
        public void Context_Student_HasEnrollments()
        {
            TestHelper.SeedDatabase(_context);

            var student = _context.Students
                .Include(s => s.Enrollments)
                .First(s => s.LastName == "Alexander");

            Assert.NotNull(student.Enrollments);
            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Context_Course_HasDepartmentRelationship()
        {
            TestHelper.SeedDatabase(_context);

            var course = _context.Courses
                .Include(c => c.Department)
                .First(c => c.CourseID == 1050);

            Assert.NotNull(course.Department);
            Assert.Equal("Engineering", course.Department!.Name);
        }

        [Fact]
        public void Context_CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "Test",
                IsRead = false
            };
            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Test notification", retrieved.Message);
        }
    }
}

