        public void Initialize_DepartmentHasAdministrator()
        {
            var context = TestHelper.CreateContext();
            DbInitializer.Initialize(context);

            var english = context.Departments
                .Include(d => d.Administrator)
                .First(d => d.Name == "English");

            Assert.NotNull(english.Administrator);
            Assert.Equal("Abercrombie", english.Administrator!.LastName);
            context.Dispose();
        }
    }
}

