[Fact]
public void Index_WithInstructorAndCourseId_SetsViewBagCourseID()
{
    // Get an instructor with course assignments
    var instructor = _context.Instructors
        .Include(i => i.CourseAssignments)
        .First(i => i.CourseAssignments.Any());

    var courseId = instructor.CourseAssignments.First().CourseID;

    // Load enrollments on the course so the controller can access them
    var course = _context.Courses
        .Include(c => c.Enrollments)
        .First(c => c.CourseID == courseId);

    var result = _controller.Index(instructor.ID, courseId) as ViewResult;

    Assert.NotNull(result);
    var model = Assert.IsType<InstructorIndexData>(result!.Model);
    Assert.Equal(courseId, (int)_controller.ViewBag.CourseID);
}

